// ============================================
// NÓ: processarAgruparCards (VERSÃO 2.0)
// Compatível com novo formato do WF1 + Sprints
// ============================================

const inputWF1 = $json.dados_projeto || $json;

console.log('=== WF__2 INICIADO (v2.0) ===');

// Usa formato novo do WF1
const todosCards = inputWF1.cards || [];
const fases = inputWF1.fases || {};
const projetoInfo = inputWF1.projeto_info || { id: 0, nome: 'Projeto Desconhecido' };
const resumoWF1 = inputWF1.resumo || {};
const sprintsIdentificadas = inputWF1.sprints_identificadas || [];

console.log(`Projeto: ${projetoInfo.nome} (ID: ${projetoInfo.id})`);
console.log(`Total de cards: ${todosCards.length}`);
console.log(`Sprints identificadas: ${sprintsIdentificadas.length}`);

// ============================================
// CONFIGURAÇÕES
// ============================================
const agora = new Date();
const DIAS_ANALISE = 200;
const DIAS_RECENTE = 14;
const DIAS_ALERTA = 14;

const inicioAnalise = new Date(agora.getTime() - DIAS_ANALISE * 24 * 60 * 60 * 1000);
const inicioRecente = new Date(agora.getTime() - DIAS_RECENTE * 24 * 60 * 60 * 1000);

// ============================================
// FUNÇÕES AUXILIARES
// ============================================
function isDataRecente(dataStr, diasAtras = DIAS_RECENTE) {
  if (!dataStr) return false;
  const data = new Date(dataStr);
  const limite = new Date(agora.getTime() - diasAtras * 24 * 60 * 60 * 1000);
  return data >= limite && data <= agora;
}

function getDataEntradaFase(card, faseBuscada) {
  if (!card.logs_fase) return null;
  const log = card.logs_fase.find(l => 
    l.para && l.para.toLowerCase().includes(faseBuscada.toLowerCase())
  );
  return log ? log.data : null;
}

function formatarHoras(horas) {
  if (!horas || horas === 0) return '0h';
  if (horas < 1) return `${Math.round(horas * 60)}min`;
  return `${Math.round(horas)}h`;
}

// CORRIGIDO: Usa tempo_trabalhado_horas (real) em vez de tempo_por_fase
function calcularTempoTotal(card) {
  if (card.tempo_trabalhado_horas && card.tempo_trabalhado_horas > 0) {
    return card.tempo_trabalhado_horas;
  }
  if (card.tempo_por_fase) {
    return Object.values(card.tempo_por_fase).reduce((a, b) => a + b, 0);
  }
  return 0;
}

// ============================================
// CATEGORIZAÇÃO DOS CARDS
// ============================================

const concluidos = todosCards.filter(c => {
  if (!c.fase_atual_nome) return false;
  const fase = c.fase_atual_nome.toLowerCase();
  const isConcluido = fase.includes('conclu');

  if (!isConcluido) return false;

  const dataConclusao = getDataEntradaFase(c, 'conclu');
  return dataConclusao && new Date(dataConclusao) >= inicioAnalise;
});

const concluidosRecentes = concluidos.filter(c => {
  const dataConclusao = getDataEntradaFase(c, 'conclu');
  return isDataRecente(dataConclusao, DIAS_RECENTE);
});

const emAndamento = todosCards.filter(c => 
  c.fase_atual_nome && c.fase_atual_nome.toLowerCase().includes('andamento')
);

const emAndamentoAlerta = emAndamento.filter(c => 
  c.dias_na_fase_atual && c.dias_na_fase_atual >= DIAS_ALERTA
);

const emTestes = todosCards.filter(c => 
  c.fase_atual_nome && c.fase_atual_nome.toLowerCase().includes('teste')
);

const pendentes = todosCards.filter(c => {
  if (!c.fase_atual_nome) return false;
  const fase = c.fase_atual_nome.toLowerCase();
  return fase.includes('sprint') || fase.includes('backlog') || fase.includes('fila');
});

const outros = todosCards.filter(c => {
  if (!c.fase_atual_nome) return false;
  const fase = c.fase_atual_nome.toLowerCase();

  return !fase.includes('conclu') && 
         !fase.includes('andamento') && 
         !fase.includes('teste') &&
         !fase.includes('sprint') && 
         !fase.includes('backlog') && 
         !fase.includes('fila');
});

const cardsTravados = todosCards.filter(c => 
  c.dias_na_fase_atual && c.dias_na_fase_atual >= 30
);

// ============================================
// AGRUPAMENTO POR SPRINT
// ============================================
const cardsPorSprint = {};

sprintsIdentificadas.forEach(sprint => {
  cardsPorSprint[sprint.nome] = {
    info: sprint,
    cards: todosCards.filter(c => c.sprint_identificada === sprint.nome),
    concluidos: [],
    em_andamento: [],
    em_testes: [],
    pendentes: [],
    outros: []
  };

  cardsPorSprint[sprint.nome].cards.forEach(card => {
    const fase = (card.fase_atual_nome || '').toLowerCase();

    if (fase.includes('conclu')) {
      cardsPorSprint[sprint.nome].concluidos.push(card);
    } else if (fase.includes('andamento')) {
      cardsPorSprint[sprint.nome].em_andamento.push(card);
    } else if (fase.includes('teste')) {
      cardsPorSprint[sprint.nome].em_testes.push(card);
    } else if (fase.includes('sprint') || fase.includes('backlog') || fase.includes('fila')) {
      cardsPorSprint[sprint.nome].pendentes.push(card);
    } else {
      cardsPorSprint[sprint.nome].outros.push(card);
    }
  });
});

const cardsSemSprint = todosCards.filter(c => !c.sprint_identificada);

console.log('📊 CATEGORIZAÇÃO:');
console.log(`   Concluídos (${DIAS_ANALISE} dias): ${concluidos.length}`);
console.log(`   Concluídos recentes (${DIAS_RECENTE} dias): ${concluidosRecentes.length}`);
console.log(`   Em Andamento: ${emAndamento.length} (${emAndamentoAlerta.length} com alerta)`);
console.log(`   Em Testes: ${emTestes.length}`);
console.log(`   Pendentes: ${pendentes.length}`);
console.log(`   Outros: ${outros.length}`);
console.log(`   Travados (>30 dias): ${cardsTravados.length}`);
console.log(`   Sem sprint: ${cardsSemSprint.length}`);

// ============================================
// MOVIMENTAÇÕES RECENTES
// ============================================
const movimentacoesRecentes = [];

todosCards.forEach(card => {
  if (!card.logs_fase) return;

  card.logs_fase.forEach(log => {
    if (isDataRecente(log.data, DIAS_RECENTE)) {
      movimentacoesRecentes.push({
        card_id: card.id,
        card_titulo: card.titulo,
        card_descricao: card.descricao_limpa,
        de: log.de,
        para: log.para,
        data: log.data,
        usuario: log.usuario,
        sprint: card.sprint_identificada
      });
    }
  });
});

movimentacoesRecentes.sort((a, b) => new Date(b.data) - new Date(a.data));

console.log(`📅 Movimentações nos últimos ${DIAS_RECENTE} dias: ${movimentacoesRecentes.length}`);

// ============================================
// MÉTRICAS
// ============================================
const totalHorasConcluidas = concluidos.reduce((sum, c) => sum + calcularTempoTotal(c), 0);
const totalHorasRecentesConcluidas = concluidosRecentes.reduce((sum, c) => sum + calcularTempoTotal(c), 0);
const totalPontosConcluidos = concluidos.reduce((sum, c) => sum + (c.pontos_totais || 0), 0);

// ============================================
// OUTPUT
// ============================================
const resultado = {
  projeto_info: projetoInfo,
  fases: fases,

  periodo_analise: {
    inicio: inicioAnalise.toISOString().split('T')[0],
    fim: agora.toISOString().split('T')[0],
    dias: DIAS_ANALISE,
    dias_recente: DIAS_RECENTE
  },

  sprints: {
    total: sprintsIdentificadas.length,
    lista: sprintsIdentificadas,
    por_sprint: cardsPorSprint
  },

  analise: {
    concluidos: {
      total: concluidos.length,
      recentes: concluidosRecentes.length,
      cards: concluidos.map(c => ({
        id: c.id,
        titulo: c.titulo,
        descricao: c.descricao_limpa ? c.descricao_limpa.substring(0, 300) : '',
        tempo_total_horas: Math.round(calcularTempoTotal(c)),
        tempo_formatado: formatarHoras(calcularTempoTotal(c)),
        pontos: c.pontos_totais,
        responsaveis: c.responsaveis || [],
        sprint: c.sprint_identificada,
        data_conclusao: getDataEntradaFase(c, 'conclu'),
        is_recente: concluidosRecentes.some(cr => cr.id === c.id)
      }))
    },

    em_andamento: {
      total: emAndamento.length,
      com_alerta: emAndamentoAlerta.length,
      cards: emAndamento.map(c => ({
        id: c.id,
        titulo: c.titulo,
        descricao: c.descricao_limpa ? c.descricao_limpa.substring(0, 200) : '',
        tempo_total_horas: Math.round(calcularTempoTotal(c)),
        dias_na_fase: c.dias_na_fase_atual,
        alerta: c.dias_na_fase_atual >= DIAS_ALERTA,
        responsaveis: c.responsaveis || [],
        sprint: c.sprint_identificada
      }))
    },

    em_testes: {
      total: emTestes.length,
      cards: emTestes.map(c => ({
        id: c.id,
        titulo: c.titulo,
        descricao: c.descricao_limpa ? c.descricao_limpa.substring(0, 200) : '',
        tempo_total_horas: Math.round(calcularTempoTotal(c)),
        dias_na_fase: c.dias_na_fase_atual,
        responsaveis: c.responsaveis || [],
        sprint: c.sprint_identificada
      }))
    },

    pendentes: {
      total: pendentes.length,
      cards: pendentes.map(c => ({
        id: c.id,
        titulo: c.titulo,
        fase: c.fase_atual_nome,
        sprint: c.sprint_identificada
      }))
    },

    outros: {
      total: outros.length,
      cards: outros.map(c => ({
        id: c.id,
        titulo: c.titulo,
        fase: c.fase_atual_nome,
        dias_na_fase: c.dias_na_fase_atual,
        sprint: c.sprint_identificada
      }))
    },

    alertas: {
      cards_travados: cardsTravados.map(c => ({
        id: c.id,
        titulo: c.titulo,
        fase: c.fase_atual_nome,
        dias_parado: c.dias_na_fase_atual,
        sprint: c.sprint_identificada
      })),
      cards_em_andamento_alerta: emAndamentoAlerta.map(c => ({
        id: c.id,
        titulo: c.titulo,
        dias_na_fase: c.dias_na_fase_atual,
        sprint: c.sprint_identificada
      }))
    },

    movimentacoes_recentes: {
      total: movimentacoesRecentes.length,
      lista: movimentacoesRecentes.slice(0, 50)
    },

    metricas: {
      total_horas_concluidas: Math.round(totalHorasConcluidas),
      total_horas_recentes: Math.round(totalHorasRecentesConcluidas),
      total_pontos_concluidos: totalPontosConcluidos,
      cards_sem_sprint: cardsSemSprint.length,
      taxa_progresso: concluidos.length > 0 && (concluidos.length + pendentes.length) > 0
        ? ((concluidos.length / (concluidos.length + pendentes.length)) * 100).toFixed(1) + '%'
        : 'N/A'
    }
  }
};

console.log('');
console.log('✅ Processamento concluído');
console.log(`📊 Métricas: ${resultado.analise.metricas.total_horas_concluidas}h total, ${resultado.analise.metricas.total_horas_recentes}h recentes`);

return [{ json: resultado }];

// ============================================
// NÓ: montarPromptGroq (VERSÃO 2.1)
// Ajuste: Usa título quando descrição vazia
// Ajuste: Força descrição individual por card
// ============================================

const dados = $json;
const analise = dados.analise;
const projetoInfo = dados.projeto_info;
const periodo = dados.periodo_analise;
const sprints = dados.sprints;

console.log('=== GERANDO PROMPT PARA IA (v2.1) ===');

// ============================================
// FUNÇÕES AUXILIARES
// ============================================
function formatarData(dataStr) {
  if (!dataStr) return 'N/A';
  const data = new Date(dataStr);
  return data.toLocaleDateString('pt-BR', { day: '2-digit', month: '2-digit', year: 'numeric' });
}

// 🆕 MELHORIA: Usa título como fallback quando descrição vazia
function obterDescricaoCard(card) {
  // Se tem descrição, usa ela
  if (card.descricao_limpa && card.descricao_limpa.trim() !== '') {
    const desc = card.descricao_limpa.trim();
    return desc.length > 150 ? desc.substring(0, 150) + '...' : desc;
  }

  // Se não tem descrição, interpreta o título
  if (card.titulo) {
    // Remove prefixos comuns como [DJANGO], [FRONT], etc
    let titulo = card.titulo.replace(/^\[.*?\]\s*-?\s*/i, '').trim();
    return `tarefa de ${titulo.toLowerCase()}`;
  }

  return 'sem descrição disponível';
}

// 🆕 MELHORIA: Formata tempo de forma mais clara
function formatarTempo(horas) {
  if (!horas || horas === 0) return null;
  if (horas < 1) return `${Math.round(horas * 60)} minutos`;
  if (horas < 24) return `${Math.round(horas)}h`;
  const dias = Math.floor(horas / 24);
  const horasRestantes = Math.round(horas % 24);
  return `${dias} dias e ${horasRestantes}h (~${Math.round(horas)}h total)`;
}

// 🆕 MELHORIA: Classifica complexidade baseado em horas ou pontos
function classificarComplexidade(card) {
  const horas = card.tempo_por_fase ? Object.values(card.tempo_por_fase).reduce((a,b) => a+b, 0) : 0;
  const pontos = card.pontos_totais || 0;

  if (pontos >= 3 || horas >= 100) return 'alta complexidade';
  if (pontos >= 2 || horas >= 40) return 'média complexidade';
  if (pontos >= 1 || horas >= 10) return 'baixa complexidade';
  return null;
}

// ============================================
// MONTA CONTEXTO POR SPRINT (MELHORADO)
// ============================================
let textoSprints = '';

if (sprints.lista && sprints.lista.length > 0) {
  textoSprints = sprints.lista.map(sprint => {
    const dadosSprint = sprints.por_sprint[sprint.nome];
    if (!dadosSprint || dadosSprint.cards.length === 0) return '';

    const concluidos = dadosSprint.concluidos;
    const emAndamento = dadosSprint.em_andamento;
    const emTestes = dadosSprint.em_testes;
    const pendentes = dadosSprint.pendentes;

    let textoSprint = `\n### ${sprint.nome} (${sprint.total} cards)\n`;
    textoSprint += `Período: ${formatarData(sprint.periodo.inicio)} a ${formatarData(sprint.periodo.fim)}\n\n`;

    // 🆕 Cards concluídos - DETALHAMENTO INDIVIDUAL
    if (concluidos.length > 0) {
      textoSprint += `**CONCLUÍDOS (${concluidos.length}):**\n`;
      concluidos.forEach(c => {
        const tempo = c.tempo_por_fase ? Math.round(Object.values(c.tempo_por_fase).reduce((a,b) => a+b, 0)) : 0;
        const complexidade = classificarComplexidade(c);

        textoSprint += `• Card #${c.id}: "${c.titulo}"\n`;
        textoSprint += `  → O QUE FAZ: ${obterDescricaoCard(c)}\n`;
        textoSprint += `  → TEMPO GASTO: ${tempo}h${complexidade ? ` (${complexidade})` : ''}\n`;
        textoSprint += `  → PONTOS: ${c.pontos_totais || 0}\n`;
        textoSprint += `  → RESPONSÁVEIS: ${(c.responsaveis || []).join(', ') || 'Não atribuído'}\n\n`;
      });
    }

    // 🆕 Cards em andamento - DETALHAMENTO INDIVIDUAL
    if (emAndamento.length > 0) {
      textoSprint += `**EM ANDAMENTO (${emAndamento.length}):**\n`;
      emAndamento.forEach(c => {
        const tempo = c.tempo_por_fase ? Math.round(Object.values(c.tempo_por_fase).reduce((a,b) => a+b, 0)) : 0;

        textoSprint += `• Card #${c.id}: "${c.titulo}"\n`;
        textoSprint += `  → O QUE FAZ: ${obterDescricaoCard(c)}\n`;
        textoSprint += `  → TEMPO JÁ GASTO: ${tempo}h\n`;
        textoSprint += `  → DIAS EM ANDAMENTO: ${c.dias_na_fase_atual || '?'} dias\n`;
        textoSprint += `  → RESPONSÁVEIS: ${(c.responsaveis || []).join(', ') || 'Não atribuído'}\n\n`;
      });
    }

    // 🆕 Cards em testes - DETALHAMENTO INDIVIDUAL
    if (emTestes.length > 0) {
      textoSprint += `**EM TESTES/AGUARDANDO VALIDAÇÃO (${emTestes.length}):**\n`;
      emTestes.forEach(c => {
        const tempo = c.tempo_por_fase ? Math.round(Object.values(c.tempo_por_fase).reduce((a,b) => a+b, 0)) : 0;

        textoSprint += `• Card #${c.id}: "${c.titulo}"\n`;
        textoSprint += `  → O QUE FAZ: ${obterDescricaoCard(c)}\n`;
        textoSprint += `  → TEMPO TOTAL: ${tempo}h\n`;
        textoSprint += `  → DIAS EM TESTES: ${c.dias_na_fase_atual || '?'} dias aguardando validação\n\n`;
      });
    }

    // Cards pendentes
    if (pendentes.length > 0) {
      textoSprint += `**PENDENTES/NÃO INICIADOS (${pendentes.length}):**\n`;
      pendentes.forEach(c => {
        textoSprint += `• Card #${c.id}: "${c.titulo}" → ${obterDescricaoCard(c)}\n`;
      });
      textoSprint += '\n';
    }

    return textoSprint;
  }).filter(t => t !== '').join('\n---\n');
} else {
  textoSprints = 'Nenhuma sprint identificada no período.';
}

// ============================================
// CARDS SEM SPRINT
// ============================================
let textoSemSprint = '';
const cardsSemSprint = analise.outros.cards.filter(c => !c.sprint);
const backlogSemSprint = analise.pendentes.cards.filter(c => !c.sprint);

if (cardsSemSprint.length > 0 || backlogSemSprint.length > 0) {
  textoSemSprint = '\n### Cards fora de Sprint\n';

  if (backlogSemSprint.length > 0) {
    textoSemSprint += `**No Backlog (${backlogSemSprint.length}):**\n`;
    backlogSemSprint.slice(0, 10).forEach(c => {
      textoSemSprint += `• Card #${c.id}: "${c.titulo}"\n`;
    });
    if (backlogSemSprint.length > 10) {
      textoSemSprint += `... e mais ${backlogSemSprint.length - 10} cards\n`;
    }
    textoSemSprint += '\n';
  }

  if (cardsSemSprint.length > 0) {
    textoSemSprint += `**Em outras fases (${cardsSemSprint.length}):**\n`;
    cardsSemSprint.forEach(c => {
      textoSemSprint += `• Card #${c.id}: "${c.titulo}" - ${c.fase} (há ${c.dias_na_fase || '?'} dias)\n`;
    });
  }
}

// ============================================
// ALERTAS
// ============================================
let textoAlertas = '';

if (analise.alertas.cards_travados.length > 0) {
  textoAlertas += '**⚠️ Cards travados (>30 dias sem movimentação):**\n';
  analise.alertas.cards_travados.forEach(c => {
    textoAlertas += `• Card #${c.id}: "${c.titulo}" - Parado há ${c.dias_parado} dias em "${c.fase}"\n`;
  });
  textoAlertas += '\n';
}

if (analise.alertas.cards_em_andamento_alerta.length > 0) {
  textoAlertas += '**⚠️ Cards em andamento há muito tempo (>14 dias):**\n';
  analise.alertas.cards_em_andamento_alerta.forEach(c => {
    textoAlertas += `• Card #${c.id}: "${c.titulo}" - Há ${c.dias_na_fase} dias em andamento\n`;
  });
}

if (!textoAlertas) {
  textoAlertas = 'Nenhum alerta crítico identificado.';
}

// ============================================
// MOVIMENTAÇÕES RECENTES
// ============================================
let textoMovimentacoes = '';

if (analise.movimentacoes_recentes && analise.movimentacoes_recentes.total > 0) {
  const mov = analise.movimentacoes_recentes.lista.slice(0, 15);
  textoMovimentacoes = `**Últimas ${mov.length} movimentações (${periodo.dias_recente} dias):**\n`;
  mov.forEach(m => {
    textoMovimentacoes += `• ${formatarData(m.data)}: Card #${m.card_id} - ${m.de} → ${m.para}\n`;
  });
} else {
  textoMovimentacoes = 'Nenhuma movimentação nos últimos ' + periodo.dias_recente + ' dias.';
}

// ============================================
// PROMPT PRINCIPAL (MELHORADO)
// ============================================
const prompt = `Você é um analista de projetos sênior. Gere um **acompanhamento semanal para coordenadores** baseado nos dados do Neat.

---

## PROJETO: ${projetoInfo.nome} (ID: ${projetoInfo.id})
**Período:** ${periodo.inicio} a ${periodo.fim}
**Total de cards:** ${analise.concluidos.total + analise.em_andamento.total + analise.em_testes.total + analise.pendentes.total + analise.outros.total}
**Sprints:** ${sprints.total}

---

## DADOS POR SPRINT

${textoSprints}

${textoSemSprint}

---

## ALERTAS

${textoAlertas}

---

## MOVIMENTAÇÕES RECENTES

${textoMovimentacoes}

---

## MÉTRICAS

- Horas em cards concluídos: ${analise.metricas.total_horas_concluidas}h
- Horas recentes (${periodo.dias_recente} dias): ${analise.metricas.total_horas_recentes}h
- Pontos concluídos: ${analise.metricas.total_pontos_concluidos}
- Cards em testes: ${analise.em_testes.total}
- Taxa de progresso: ${analise.metricas.taxa_progresso}

---

## 🎯 INSTRUÇÕES CRÍTICAS - LEIA COM ATENÇÃO

### FORMATO DO RELATÓRIO:

**1. RESUMO DA SEMANA** (2-3 frases)

**2. PROGRESSO POR SPRINT**

### ⚠️ REGRA OBRIGATÓRIA: DESCREVA CADA CARD INDIVIDUALMENTE

Para CADA card importante, você DEVE escrever no seguinte formato:

✅ **EXEMPLO CORRETO:**
"O card #12912, que realiza a **criação do projeto e app base** do Django, consumiu **319h de desenvolvimento** e está em testes há 127 dias aguardando validação. Esse é um card de **alta complexidade** que estabelece a fundação do sistema."

"O card #12931, responsável pelo **Release 2 do projeto**, já acumulou **3.358h** e permanece em andamento há 104 dias. Os cards #12926 e #12927, que implementam os **endpoints, views, serializers e permissões da API-PROJETOS**, estão em testes há 78 dias após consumirem cerca de **647h cada**."

